queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?categoryname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasFilm_Festivals ?parent . } GROUP BY ?child }
  ?child p:categoryName ?categoryname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Film_Festivals } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?categoryname WHERE {
  ?film_festival_categories a :Film_Festival_Categories .
  ?categories a :Categories .
  ?film_festival_categories p:hasCategories ?categories .
  ?film_festivals a :Film_Festivals .
  ?film_festival_categories p:hasFilm_Festivals ?film_festivals .
  ?film_festivals p:name ?name .
  ?categories p:categoryName ?categoryname .
} }
  collective: { SELECT ?categoryname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCategories ?child ; p:hasFilm_Festivals ?parent . } GROUP BY ?child }
  ?child p:categoryName ?categoryname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Film_Festivals } }
  FILTER(?nf = ?total)
} }
}
